// STEP 0: Validate Gabriel's request and prepare pipeline context
const crypto = require('crypto');
const body = $json.body;

const required = ['artifact_id', 'creator_id', 'usage_type', 'gross_amount', 'currency'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`Gabriel evidence request missing fields: ${missing.join(', ')}`);
}

const bundleId = `bundle-${crypto.randomUUID()}`;
const timestamp = new Date().toISOString();

return [{
  json: {
    ...body,
    _pipeline: {
      bundle_id: bundleId,
      initiated_by: 'GABRIEL',
      initiated_at: timestamp,
      stage: 'validated'
    }
  }
}];

// CONSENT BLOCKED — halt pipeline, return evidence of denial
const crypto = require('crypto');
const pipeline = $input.first().json._pipeline || {};
const original = $input.first().json;

return [{
  json: {
    schema_version: '1.0.0',
    bundle_id: pipeline.bundle_id || `bundle-${crypto.randomUUID()}`,
    created_at: new Date().toISOString(),
    status: 'BLOCKED',
    blocked_by: 'CONSENT_CASCADE',
    reason: original.body?.reason || 'Consent verification failed',
    creator_id: original.creator_id,
    artifact_id: original.artifact_id,
    truth_strip: {
      consent: { status: 'blocked', refs: [] },
      provenance: { status: 'pending', manifest_id: 'N/A' },
      receipt_75_25: { status: 'missing', receipt_id: 'N/A', rule: '75_25' },
      memory: { status: 'failed', memcell_ids: [] },
      risk: { level: 'stop', notes: 'Consent cascade returned blocked. No artifact may leave without consent clearance.' }
    }
  }
}];

// CONSENT CLEARED — extract clearance token, merge back into pipeline
const consentResult = $json;
const items = $input.all();

// Walk back to find original request data
const original = items[0]?.json || {};

return [{
  json: {
    ...original,
    _pipeline: {
      ...(original._pipeline || {}),
      stage: 'consent_cleared',
      clearance_token: consentResult.body?.clearance_token || consentResult.clearance_token || 'token_cleared',
      consent_refs: consentResult.body?.consent_refs || []
    }
  }
}];

// Merge receipt into pipeline
const receiptResult = $json;
const items = $input.all();
const original = items[0]?.json || {};

const receipt = receiptResult.body || receiptResult;

return [{
  json: {
    ...original,
    _receipt: receipt,
    _pipeline: {
      ...(original._pipeline || {}),
      stage: 'receipt_generated',
      receipt_id: receipt.receipt_id || 'pending'
    }
  }
}];

// Merge provenance manifest into pipeline
const manifestResult = $json;
const items = $input.all();
const original = items[0]?.json || {};

const manifest = manifestResult.body || manifestResult;

return [{
  json: {
    ...original,
    _manifest: manifest,
    _pipeline: {
      ...(original._pipeline || {}),
      stage: 'provenance_signed',
      manifest_id: manifest.manifest_id || 'pending'
    }
  }
}];

// Build the EchoMoment for this evidence event
const crypto = require('crypto');
const data = $json;
const echo = data.echo || {};

const echoMoment = {
  schema_version: '1.0.0',
  echo_id: `echo-${crypto.randomUUID()}`,
  moment_type: echo.moment_type || 'artifact',
  title: echo.title || data.artifact_title || `Evidence: ${data.artifact_id}`,
  narrative: echo.narrative || `Gabriel triggered evidence generation for artifact ${data.artifact_id}. Consent cleared. Receipt issued at 75/25. Provenance manifest signed. Truth bundle assembled.`,
  created_at: new Date().toISOString(),
  creator: {
    actor_id: data.creator_id,
    display_name: data.creator_name || data.creator_id,
    brand_home: 'NOIZY'
  },
  sovereignty: {
    consent_required: true,
    provenance_required: true,
    receipt_required: true,
    never_clause_classes: data.blocked_uses || ['nsfw', 'political_persuasion', 'medical_advice', 'sublicense']
  },
  sensory: {
    tags: echo.tags || [data.artifact_type || 'audio', 'evidence', 'gabriel-triggered'],
    mood: echo.mood || ['resolute', 'verified']
  },
  accessibility: { deaf_hh_ready: true, low_sensory_ready: true },
  links: {
    artifact_ids: [data.artifact_id],
    manifest_ids: [data._pipeline.manifest_id],
    receipt_ids: [data._pipeline.receipt_id],
    memcell_ids: []
  }
};

return [{
  json: {
    ...data,
    _echo: echoMoment,
    _pipeline: {
      ...data._pipeline,
      stage: 'echo_created',
      echo_id: echoMoment.echo_id
    }
  }
}];

// ASSEMBLE THE ARTIFACT TRUTH BUNDLE
// This is the final output — the complete evidence package
// matching /schemas/ArtifactTruthBundle.schema.json
const data = $json;

const bundle = {
  schema_version: '1.0.0',
  bundle_id: data._pipeline.bundle_id,
  created_at: new Date().toISOString(),

  echo_moment: data._echo,
  receipt: data._receipt,
  manifest: data._manifest,

  truth_strip: {
    consent: {
      status: 'clear',
      refs: data._pipeline.consent_refs || [data._pipeline.clearance_token]
    },
    provenance: {
      status: 'signed',
      manifest_id: data._pipeline.manifest_id
    },
    receipt_75_25: {
      status: 'emitted',
      receipt_id: data._pipeline.receipt_id,
      rule: '75_25'
    },
    memory: {
      status: 'written',
      memcell_ids: data._echo?.links?.memcell_ids || []
    },
    risk: {
      level: 'safe',
      notes: 'Full evidence chain: consent cleared → receipt 75/25 emitted → provenance manifest signed → echo moment recorded. Gabriel-verified.'
    }
  },

  _pipeline_meta: {
    initiated_by: data._pipeline.initiated_by,
    initiated_at: data._pipeline.initiated_at,
    completed_at: new Date().toISOString(),
    stages_completed: ['validated', 'consent_cleared', 'receipt_generated', 'provenance_signed', 'echo_created', 'bundle_assembled'],
    total_stages: 6
  }
};

return [{ json: bundle }];

// Final assembly — attach Gabriel's confirmation and clean up pipeline internals
const items = $input.all();
const bundle = items[0]?.json || {};
const gabrielResponse = bundle.message?.content || bundle.body?.message?.content || 'Gabriel offline — evidence stands on its own.';

// Remove internal pipeline metadata from final output
const cleanBundle = { ...bundle };
delete cleanBundle._pipeline_meta;
delete cleanBundle.message;
delete cleanBundle.body;

return [{
  json: {
    ...cleanBundle,
    gabriel_confirmation: gabrielResponse,
    _pipeline_meta: {
      initiated_by: 'GABRIEL',
      completed_at: new Date().toISOString(),
      stages_completed: ['validated', 'consent_cleared', 'receipt_generated', 'provenance_signed', 'echo_created', 'bundle_assembled', 'stored', 'gabriel_confirmed'],
      total_stages: 8,
      status: 'COMPLETE'
    }
  }
}];
